from google_adk import Agent, trace
from collections import defaultdict

def detect_circular_delegation(trace):
    agent_calls = defaultdict(int)
    for step in trace.steps:
        if step.type == 'DELEGATION':
            agent_calls[step.from_agent] += 1
            if agent_calls[step.from_agent] > 5:
                return {'violation': 'CIRCULAR_DELEGATION', 'agent': step.from_agent}
    return None

def detect_model_safety_drift(session):
    models_used = [turn.model for turn in session.turns]
    if 'gemini-1.5-flash' in models_used and 'gemini-1.5-pro' in models_used:
        return {
            'violation': 'SAFETY_DRIFT',
            'models': list(set(models_used)),
            'risk': 'Inconsistent safety filtering'
        }
    return None

