from google_adk import Agent
class GovernedAgent(Agent):
    def __init__(self, *args, max_delegations=3, **kwargs):
        super().__init__(*args, **kwargs)
        self.delegation_count = 0
        self.max_delegations = max_delegations

    async def delegate(self, target_agent, context):
        if self.delegation_count >= self.max_delegations:
            return {'error': 'MAX_DELEGATIONS_EXCEEDED'}
        self.delegation_count += 1
        return await target_agent.execute(context)

from google_adk.sessions import Session
class SafeSession(Session):
    def __init__(self, model_name='gemini-1.5-pro'):
        super().__init__()
        self._model_name = model_name

    async def execute(self, agent, input):
        agent.model = self._model_name  # Enforce consistent model
        return await super().execute(agent, input)

def state_pruning_middleware(session_state):
    if len(session_state) > 50:
        # Keep latest 50 turns
        session_state['history'] = session_state['history'][-50:]
    # Remove agent-specific temp data
    for agent_id in session_state.get('agents', []):
        if 'temp_context' in session_state[agent_id]:
            del session_state[agent_id]['temp_context']
    return session_state
